// Generated by Cypress Author — 2026-05-25
// Covers: Running Tracker Gear UI (ShoeRotation component on Dashboard)
//   Rendered inside /main/running/dashboard — ShoeRotation is always mounted
//   on the dashboard page (not a separate route).
//
// AUTH STRATEGY:
//   cy.setupApiAuthCookies() — real Supabase session required.
//   stubRtUsers() — stubs rt_users onboarding check so (app)/layout lets us through.
//   stubDashboardMinimal() — stubs GET /api/running/v1/dashboard with minimal data
//     so the rest of the dashboard renders quickly and ShoeRotation can mount.
//   GET /api/running/v1/gear is intercepted per-test with fixture data.

import constants from '../../../fixtures/app-constants.json'

const GEAR_IDS = constants.test_ids.running_gear

/** Stub rt_users to report onboarding complete. */
const stubRtUsers = () => {
  cy.intercept('GET', '**/rest/v1/rt_users*', {
    statusCode: 200,
    body: [{ id: 'test-user-id', onboarding_complete: true }],
  }).as('rtUsersCheck')
}

/** Minimal dashboard stub so the page renders without failing. */
const stubDashboardMinimal = () => {
  cy.intercept('GET', '/api/running/v1/dashboard', {
    statusCode: 200,
    body: {
      data: {
        weekly_stats: {
          current: { distance_m: 0, duration_sec: 0, count: 0, avg_pace_sec_per_km: null },
          prev: { distance_m: 0, duration_sec: 0, count: 0, avg_pace_sec_per_km: null },
        },
        training_load: {
          acwr: null,
          acute_load_7d: null,
          chronic_load_28d: null,
          status: 'no_data',
        },
        recent_activities: [],
        calendar_activities: [],
        health_today: { logged: false, data: null },
      },
    },
  }).as('getDashboardMinimal')
}

/** Stub auto-sync so page doesn't fire a real POST on mount. */
const stubSyncStrava = () => {
  cy.intercept('POST', '/api/running/v1/auth/strava/sync', {
    statusCode: 200,
    body: { synced: 0 },
  }).as('syncStrava')
}

// ---------------------------------------------------------------------------
// A. Loading skeleton
// ---------------------------------------------------------------------------

describe('Running Gear UI — Loading skeleton', () => {
  before(() => {
    cy.setupApiAuthCookies()
  })

  it('shows #gearLoadingSkeleton while gear fetch is pending', () => {
    cy.setupApiAuthCookies()
    stubRtUsers()
    stubDashboardMinimal()
    stubSyncStrava()

    cy.intercept('GET', '/api/running/v1/gear', (req) => {
      req.reply((res) => {
        res.setDelay(1000)
        res.send({ statusCode: 200, body: { data: [] } })
      })
    }).as('getGearDelayed')

    cy.viewport(1280, 720)
    cy.visit('/main/running/dashboard')
    cy.wait('@getDashboardMinimal')

    cy.get(`#${GEAR_IDS.loading_skeleton}`).should('exist')
  })
})

// ---------------------------------------------------------------------------
// B. Happy path — active gear renders
// ---------------------------------------------------------------------------

describe('Running Gear UI — Happy path', () => {
  before(() => {
    cy.setupApiAuthCookies()
  })

  beforeEach(() => {
    cy.viewport(1280, 720)
    cy.setupApiAuthCookies()
    stubRtUsers()
    stubDashboardMinimal()
    stubSyncStrava()

    cy.intercept('GET', '/api/running/v1/gear', {
      statusCode: 200,
      body: {
        data: [
          {
            id: 'gear-1',
            name: 'Nike Vaporfly 3',
            distance_m: 320000,
            retired: false,
            category: 'race',
            retirement_km: 800,
            notification_distance_m: 500000,
          },
          {
            id: 'gear-2',
            name: 'ASICS Gel-Nimbus 25',
            distance_m: 210000,
            retired: false,
            category: 'daily',
            retirement_km: null,
            notification_distance_m: null,
          },
        ],
      },
    }).as('getGear')

    cy.visit('/main/running/dashboard')
    cy.wait('@getDashboardMinimal')
    cy.wait('@getGear')
  })

  it('renders #gearList with active shoes', () => {
    cy.get(`#${GEAR_IDS.list}`).should('exist')
    cy.get(`#${GEAR_IDS.list}`).find('li').should('have.length', 2)
  })

  it('#gearCard shows shoe name', () => {
    cy.get(`#${GEAR_IDS.gear_card}`).first().should('contain', 'Nike Vaporfly 3')
  })

  it('#gearCard shows distance in km with 2 decimal places', () => {
    // 320000m → 320.00 km
    cy.get(`#${GEAR_IDS.gear_card}`).first().should('contain', '320.00')
  })
})

