// ---------------------------------------------------------------------------
// D. Error state — API 500
// ---------------------------------------------------------------------------

describe('Running Gear UI — Error state', () => {
  before(() => {
    cy.setupApiAuthCookies()
  })

  beforeEach(() => {
    cy.viewport(1280, 720)
    cy.setupApiAuthCookies()
    stubRtUsers()
    stubDashboardMinimal()
    stubSyncStrava()

    cy.intercept('GET', '/api/running/v1/gear', {
      statusCode: 500,
      body: { error: 'Internal server error' },
    }).as('getGearError')

    cy.visit('/main/running/dashboard')
    cy.wait('@getDashboardMinimal')
    cy.wait('@getGearError')
  })

  it('shows #gearError on API 500', () => {
    cy.get(`#${GEAR_IDS.error}`, { timeout: 8000 }).should('be.visible')
  })

  it('shows a retry button in error state', () => {
    cy.get(`#${GEAR_IDS.error}`).contains('Try again').should('be.visible')
  })

  it('does not show #gearLoadingSkeleton after error resolves', () => {
    cy.get(`#${GEAR_IDS.loading_skeleton}`).should('not.exist')
  })
})

