// F. Limit tabs — both Manual and Strava set
// ---------------------------------------------------------------------------

describe('Running Gear UI — Limit tabs: Manual and Strava', () => {
  before(() => {
    cy.setupApiAuthCookies()
  })

  beforeEach(() => {
    cy.viewport(1280, 720)
    cy.setupApiAuthCookies()
    stubRtUsers()
    stubDashboardMinimal()
    stubSyncStrava()

    cy.intercept('GET', '/api/running/v1/gear', {
      statusCode: 200,
      body: {
        data: [
          {
            id: 'gear-both',
            name: 'Saucony Endorphin Pro 3',
            distance_m: 400000,
            retired: false,
            category: 'tempo',
            retirement_km: 800,
            notification_distance_m: 500000,
          },
        ],
      },
    }).as('getGearBoth')

    cy.visit('/main/running/dashboard')
    cy.wait('@getDashboardMinimal')
    cy.wait('@getGearBoth')
  })

  it('Manual tab shows "800.00 km" when retirement_km=800 (default tab when manual is set)', () => {
    // Default tab is Manual when retirement_km is set
    cy.get(`#${GEAR_IDS.gear_card}`).should('contain', 'Manual · 800.00 km')
  })

  it('Strava tab shows "500.00 km" when notification_distance_m=500000', () => {
    cy.get(`#${GEAR_IDS.gear_card}`).should('contain', 'Strava · 500.00 km')
  })

  it('clicking Strava tab when Manual is active switches displayed limit', () => {
    // Manual is the default; click Strava tab
    cy.get(`#${GEAR_IDS.gear_card}`)
      .contains('button', /^Strava/)
      .click()
    // After clicking Strava tab the Strava tab should be aria-pressed=true
    cy.get(`#${GEAR_IDS.gear_card}`)
      .contains('button', /^Strava/)
      .should('have.attr', 'aria-pressed', 'true')
  })
})

