describe('Running Gear UI — Edit form', () => {
  before(() => {
    cy.setupApiAuthCookies()
  })

  beforeEach(() => {
    cy.viewport(1280, 720)
    cy.setupApiAuthCookies()
    stubRtUsers()
    stubDashboardMinimal()
    stubSyncStrava()

    cy.intercept('GET', '/api/running/v1/gear', {
      statusCode: 200,
      body: {
        data: [
          {
            id: 'gear-edit',
            name: 'New Balance FuelCell',
            distance_m: 80000,
            retired: false,
            category: null,
            retirement_km: null,
            notification_distance_m: null,
          },
        ],
      },
    }).as('getGearEdit')

    cy.visit('/main/running/dashboard')
    cy.wait('@getDashboardMinimal')
    cy.wait('@getGearEdit')
  })

  it('clicking the edit pencil button opens the edit form', () => {
    cy.get(`#${GEAR_IDS.gear_card}`).find('button[aria-label^="Edit"]').click()
    cy.get(`#${GEAR_IDS.save_btn}`).should('be.visible')
  })

  it('#gearSaveBtn is present in the edit form', () => {
    cy.get(`#${GEAR_IDS.gear_card}`).find('button[aria-label^="Edit"]').click()
    cy.get(`#${GEAR_IDS.save_btn}`).should('exist')
    cy.get(`#${GEAR_IDS.save_btn}`).should('contain', 'Save')
  })

  it('Cancel button closes the edit form', () => {
    cy.get(`#${GEAR_IDS.gear_card}`).find('button[aria-label^="Edit"]').click()
    cy.get(`#${GEAR_IDS.save_btn}`).should('be.visible')

    cy.get(`#${GEAR_IDS.gear_card}`).find('button[aria-label="Cancel editing"]').click()

    cy.get(`#${GEAR_IDS.save_btn}`).should('not.exist')
  })
})
